/**
 * FindReplaceDialog — find and replace text across task fields.
 * Mirrors MS Project's Ctrl+H Find & Replace.
 */

import React, { useState, useCallback, useMemo } from 'react';
import {
  Dialog, DialogTitle, DialogContent, DialogActions, Button,
  TextField, Box, Typography, FormControlLabel, Checkbox,
  Select, MenuItem, InputLabel, FormControl, List, ListItem, ListItemText,
} from '@mui/material';
import { useUIStore, useProjectStore } from '../../stores';

const SEARCHABLE_FIELDS = [
  { value: 'name', label: 'Task Name' },
  { value: 'notes', label: 'Notes' },
  { value: 'wbsCode', label: 'WBS' },
  { value: 'resourceNames', label: 'Resource Names' },
] as const;

interface MatchResult {
  taskId: string;
  taskName: string;
  field: string;
  value: string;
}

const FindReplaceDialog: React.FC = () => {
  const openDialog = useUIStore((s) => s.openDialog);
  const closeDialog = useUIStore((s) => s.closeDialog);
  const open = openDialog === 'findReplace';

  const tasks = useProjectStore((s) => s.tasks);
  const batchUpdateTasks = useProjectStore((s) => s.batchUpdateTasks);
  const showSnackbar = useUIStore((s) => s.showSnackbar);

  const [findText, setFindText] = useState('');
  const [replaceText, setReplaceText] = useState('');
  const [matchCase, setMatchCase] = useState(false);
  const [wholeWord, setWholeWord] = useState(false);
  const [searchField, setSearchField] = useState<string>('name');
  const [matches, setMatches] = useState<MatchResult[]>([]);

  const doFind = useCallback(() => {
    if (!findText) { setMatches([]); return; }

    const results: MatchResult[] = [];
    const normalizedSearch = matchCase ? findText : findText.toLowerCase();

    for (const task of tasks) {
      const value = String((task as unknown as Record<string, unknown>)[searchField] ?? '');
      const normalizedValue = matchCase ? value : value.toLowerCase();
      let found = false;

      if (wholeWord) {
        const regex = new RegExp(`\\b${normalizedSearch.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')}\\b`, matchCase ? '' : 'i');
        found = regex.test(value);
      } else {
        found = normalizedValue.includes(normalizedSearch);
      }

      if (found) {
        results.push({ taskId: task.id, taskName: task.name, field: searchField, value });
      }
    }
    setMatches(results);
  }, [findText, tasks, searchField, matchCase, wholeWord]);

  const doReplace = useCallback(async (all: boolean) => {
    if (!findText || matches.length === 0) return;

    const toUpdate = all ? matches : matches.slice(0, 1);
    const updates = toUpdate.map((m) => {
      const oldVal = String((tasks.find((t) => t.id === m.taskId) as unknown as Record<string, unknown>)?.[m.field] ?? '');
      let newVal: string;
      if (matchCase) {
        newVal = oldVal.split(findText).join(replaceText);
      } else {
        const regex = new RegExp(findText.replace(/[.*+?^${}()|[\]\\]/g, '\\$&'), 'gi');
        newVal = oldVal.replace(regex, replaceText);
      }
      return { id: m.taskId, data: { [m.field]: newVal } };
    });

    try {
      await batchUpdateTasks(updates);
      showSnackbar(`Replaced ${updates.length} occurrence(s)`, 'success');
      doFind(); // refresh
    } catch (e: any) {
      showSnackbar(e.message, 'error');
    }
  }, [findText, replaceText, matches, matchCase, tasks, batchUpdateTasks, showSnackbar, doFind]);

  if (!open) return null;

  return (
    <Dialog open={open} onClose={closeDialog} maxWidth="sm" fullWidth>
      <DialogTitle>Find and Replace</DialogTitle>
      <DialogContent>
        <Box sx={{ display: 'flex', flexDirection: 'column', gap: 2, mt: 1 }}>
          <FormControl size="small" fullWidth>
            <InputLabel>Search In</InputLabel>
            <Select value={searchField} label="Search In" onChange={(e) => setSearchField(e.target.value)}>
              {SEARCHABLE_FIELDS.map((f) => (
                <MenuItem key={f.value} value={f.value}>{f.label}</MenuItem>
              ))}
            </Select>
          </FormControl>

          <TextField
            label="Find what"
            size="small"
            fullWidth
            value={findText}
            onChange={(e) => setFindText(e.target.value)}
            onKeyDown={(e) => { if (e.key === 'Enter') doFind(); }}
          />

          <TextField
            label="Replace with"
            size="small"
            fullWidth
            value={replaceText}
            onChange={(e) => setReplaceText(e.target.value)}
          />

          <Box sx={{ display: 'flex', gap: 2 }}>
            <FormControlLabel
              control={<Checkbox size="small" checked={matchCase} onChange={(e) => setMatchCase(e.target.checked)} />}
              label={<Typography variant="body2">Match case</Typography>}
            />
            <FormControlLabel
              control={<Checkbox size="small" checked={wholeWord} onChange={(e) => setWholeWord(e.target.checked)} />}
              label={<Typography variant="body2">Whole word</Typography>}
            />
          </Box>

          {matches.length > 0 && (
            <Box sx={{ maxHeight: 200, overflow: 'auto', border: '1px solid #E0E0E0', borderRadius: 1 }}>
              <Typography variant="caption" sx={{ px: 1, pt: 0.5, display: 'block', color: 'text.secondary' }}>
                {matches.length} match(es)
              </Typography>
              <List dense>
                {matches.map((m, i) => (
                  <ListItem key={i}>
                    <ListItemText
                      primary={m.taskName}
                      secondary={`${m.field}: "${m.value}"`}
                      primaryTypographyProps={{ fontSize: '0.8rem' }}
                      secondaryTypographyProps={{ fontSize: '0.7rem' }}
                    />
                  </ListItem>
                ))}
              </List>
            </Box>
          )}
        </Box>
      </DialogContent>
      <DialogActions>
        <Button onClick={doFind}>Find All</Button>
        <Button onClick={() => doReplace(false)} disabled={matches.length === 0}>Replace</Button>
        <Button onClick={() => doReplace(true)} disabled={matches.length === 0}>Replace All</Button>
        <Button onClick={closeDialog}>Close</Button>
      </DialogActions>
    </Dialog>
  );
};

export default FindReplaceDialog;
